//	// return true if the function was actually inlined
func s__ActuallyInlined(tls *libc.TLS, cc *CC, f uintptr) (r uint8) {
	if !((*_IRFuncData)(unsafe.Pointer((*_Function)(unsafe.Pointer(f)).Fbedata)).Fgot_inlined != 0) {
		return libc.BoolUint8(m_false != 0)
	}
	if (*_IRFuncData)(unsafe.Pointer((*_Function)(unsafe.Pointer(f)).Fbedata)).Factual_callsites > 0 {
		return libc.BoolUint8(m_false != 0)
	}
	if !((*_Function)(unsafe.Pointer(f)).FcallSites != 0) {
		return libc.BoolUint8(m_false != 0)
	}
	return libc.BoolUint8(m_true != 0)
}

// C documentation
//
//	/*
//	 * Add a new assignment "name = value" to a LoopValueSet
//	 * if value is NULL then we're adding a use rather than an assignment
//	 */
func s__AddAssignment(tls *libc.TLS, cc *CC, lvs uintptr, name uintptr, value uintptr, flags uint32, parent uintptr) (r uintptr) {
	var entry uintptr
	var v1 int32
	_, _ = entry, v1
	switch (*_AST)(unsafe.Pointer(name)).Fkind {
	case int32(_AST_EXPRLIST):
		// multiple assignment... punt on this for now
		// pretend all of these depend on a hardware register
		for name != 0 {
			s__AddAssignment(tls, cc, lvs, (*_AST)(unsafe.Pointer(name)).Fleft, x__NewAST(tls, cc, int32(_AST_HWREG), libc.UintptrFromInt32(0), libc.UintptrFromInt32(0)), uint32(m_LVFLAG_VARYMASK), libc.UintptrFromInt32(0))
			name = (*_AST)(unsafe.Pointer(name)).Fright
		}
		return libc.UintptrFromInt32(0)
	case int32(_AST_ARRAYREF):
		fallthrough
	case int32(_AST_MEMREF):
		fallthrough
	case int32(_AST_HWREG):
		fallthrough
	case int32(_AST_RANGEREF):
		// we mostly just leave array updates out of things
		return libc.UintptrFromInt32(0)
	case int32(_AST_IDENTIFIER):
		fallthrough
	case int32(_AST_LOCAL_IDENTIFIER):
	default:
		// unexpected item, bail
		(*_LoopValueSet)(unsafe.Pointer(lvs)).Fvalid = libc.BoolUint8(m_false != 0)
		return libc.UintptrFromInt32(0)
	}
	entry = s__FindName(tls, cc, lvs, name)
	if entry != 0 {
		if value != 0 {
			(*_LoopValueEntry)(unsafe.Pointer(entry)).Fhits = (*_LoopValueEntry)(unsafe.Pointer(entry)).Fhits + 1
			(*_LoopValueEntry)(unsafe.Pointer(entry)).Fvalue = value
			(*_LoopValueEntry)(unsafe.Pointer(entry)).Fparent = parent // keep track of last assignment
			**(**uint32)(__ccgo_up(entry + 32)) |= flags
		}
		return entry
	}
	entry = calloc(tls, cc, uint64(56), uint64(1))
	if value != 0 {
		v1 = int32(1)
	} else {
		v1 = 0
	}
	(*_LoopValueEntry)(unsafe.Pointer(entry)).Fhits = v1
	(*_LoopValueEntry)(unsafe.Pointer(entry)).Fname = name
	(*_LoopValueEntry)(unsafe.Pointer(entry)).Fvalue = value
	(*_LoopValueEntry)(unsafe.Pointer(entry)).Fparent = parent
	(*_LoopValueEntry)(unsafe.Pointer(entry)).Fflags = flags
	s__AddToLVS(tls, cc, lvs, entry)
	return entry
}

