func s__AddSize(tls *libc.TLS, cc *CC, sym uintptr, arg uintptr) (r int32) {
	var ptr uintptr
	var size int32
	_, _ = ptr, size
	ptr = arg
	switch (*_Symbol)(unsafe.Pointer(sym)).Fkind {
	case int32(_SYM_LOCALVAR):
		fallthrough
	case int32(_SYM_TEMPVAR):
		fallthrough
	case int32(_SYM_PARAMETER):
		size = x__TypeSize(tls, cc, *(*uintptr)(unsafe.Pointer(sym + 32)))
		size = (size + int32(m_LONG_SIZE) - int32(1)) & ^(libc.Int32FromInt32(m_LONG_SIZE) - libc.Int32FromInt32(1))
		**(**int32)(__ccgo_up(ptr)) += size
	default:
		break
	}
	return int32(1)
}

