// C documentation
//
//	//
//	// see if all instructions between ir and the label "lab" are
//	// conditional, and have condition "cond"
//	//
func s__AllInstructionsConditional(tls *libc.TLS, cc *CC, cond _IRCond1, ir uintptr, lab uintptr) (r uint8) {
	for ir != 0 {
		if (*_IR)(unsafe.Pointer(ir)).Fopc == int32(_OPC_LABEL) {
			if (*_IR)(unsafe.Pointer(ir)).Fdst == lab {
				return libc.BoolUint8(m_true != 0)
			}
			return libc.BoolUint8(m_false != 0) // some other jump may go in here
		} else {
			if !(x__IsDummy(tls, cc, ir) != 0) {
				if x__InstrSetsAnyFlags(tls, cc, ir) != 0 {
					return libc.BoolUint8(m_false != 0)
				}
				if (*_IR)(unsafe.Pointer(ir)).Fcond != cond {
					return libc.BoolUint8(m_false != 0)
				}
			}
		}
		ir = (*_IR)(unsafe.Pointer(ir)).Fnext
	}
	return libc.BoolUint8(m_false != 0)
}

func s__AllZeros(tls *libc.TLS, cc *CC, expr uintptr) (r uint8) {
	if !(expr != 0) {
		return libc.BoolUint8(m_true != 0)
	}
	if (*_AST)(unsafe.Pointer(expr)).Fkind == int32(_AST_INTEGER) && *(*_uint64_t)(unsafe.Pointer(expr + 8)) == uint64(0) {
		return libc.BoolUint8(m_true != 0)
	}
	if (*_AST)(unsafe.Pointer(expr)).Fkind == int32(_AST_STRINGPTR) {
		return libc.BoolUint8(x__AstStringLen(tls, cc, expr) == 0)
	}
	if (*_AST)(unsafe.Pointer(expr)).Fkind == int32(_AST_EXPRLIST) {
		if !(s__AllZeros(tls, cc, (*_AST)(unsafe.Pointer(expr)).Fleft) != 0) {
			return libc.BoolUint8(m_false != 0)
		}
		return s__AllZeros(tls, cc, (*_AST)(unsafe.Pointer(expr)).Fright)
	}
	return libc.BoolUint8(m_false != 0)
}

