// C documentation
//
//	/* check to see if array type A is compatible with tuple type T */
func s__ArrayCompatibleWithTuple(tls *libc.TLS, cc *CC, A uintptr, T uintptr) (r int32) {
	var Q, Qtyp, arrayLen, arrayTyp, v1 uintptr
	var expectLen, n int32
	_, _, _, _, _, _, _ = Q, Qtyp, arrayLen, arrayTyp, expectLen, n, v1
	n = 0 // length of tuple
	arrayTyp = (*_AST)(unsafe.Pointer(A)).Fleft
	arrayLen = (*_AST)(unsafe.Pointer(A)).Fright
	Q = T
	for Q != 0 {
		if (*_AST)(unsafe.Pointer(Q)).Fkind == int32(_AST_TUPLE_TYPE) {
			v1 = (*_AST)(unsafe.Pointer(Q)).Fleft
		} else {
			v1 = Q
		}
		Qtyp = v1
		if !(arrayTyp != 0) {
			arrayTyp = Qtyp
		}
		if !(x__SameTypes(tls, cc, arrayTyp, Qtyp) != 0) {
			return 0
		}
		n = n + 1
		if (*_AST)(unsafe.Pointer(Q)).Fkind == int32(_AST_TUPLE_TYPE) {
			Q = (*_AST)(unsafe.Pointer(Q)).Fright
		} else {
			Q = libc.UintptrFromInt32(0)
		}
	}
	// check for lengths compatible
	if arrayLen != 0 {
		expectLen = int32(x__EvalConstExpr(tls, cc, arrayLen))
		if expectLen != n {
			return 0
		}
	}
	return int32(1)
}

