// C documentation
//
//	//
//	// assign addresses to instructions
//	// these do not have to be exact, just close enough that they
//	// can help guide optimization, in particular whether jumps are
//	// forward or backward
//	//
func s__AssignTemporaryAddresses(tls *libc.TLS, cc *CC, irl uintptr, retlabel uintptr) {
	var addr uint32
	var ir, v2 uintptr
	_, _, _ = addr, ir, v2
	addr = uint32(0)
	ir = (*_IRList)(unsafe.Pointer(irl)).Fhead
	for {
		if !(ir != 0) {
			break
		}
		v2 = ir + 48
		*(*int32)(unsafe.Pointer(v2)) = int32(uint32(*(*int32)(unsafe.Pointer(v2))) & ^uint32(_FLAG_OPTIMIZER))
		(*_IR)(unsafe.Pointer(ir)).Faddr = addr
		if x__IsDummy(tls, cc, ir) != 0 || s__IsLabel(tls, cc, ir) != 0 {
			// do not increment
		} else {
			addr = addr + 1
		}
		if s__IsJump(tls, cc, ir) != 0 || s__IsLabel(tls, cc, ir) != 0 {
			(*_IR)(unsafe.Pointer(ir)).Faux = libc.UintptrFromInt32(0)
		}
		goto _1
	_1:
		;
		ir = (*_IR)(unsafe.Pointer(ir)).Fnext
	}
	/* on P1, flag short branches to the return */
	if retlabel != 0 && !(cc.x__gl_p2 != 0) {
		ir = (*_IRList)(unsafe.Pointer(irl)).Fhead
		for {
			if !(ir != 0) {
				break
			}
			if s__IsJump(tls, cc, ir) != 0 && x__JumpDest(tls, cc, ir) == retlabel && addr-(*_IR)(unsafe.Pointer(ir)).Faddr < uint32(m_MAX_REL_JUMP_OFFSET_LMM) {
				v2 = ir + 48
				*(*int32)(unsafe.Pointer(v2)) = int32(uint32(*(*int32)(unsafe.Pointer(v2))) | uint32(_FLAG_RET_BRANCH))
			}
			goto _3
		_3:
			;
			ir = (*_IR)(unsafe.Pointer(ir)).Fnext
		}
	}
}

