func s__AstUsesMemory(tls *libc.TLS, cc *CC, ast uintptr) (r uint8) {
	var sym uintptr
	_ = sym
	if !(ast != 0) {
		return libc.BoolUint8(m_false != 0)
	}
	switch (*_AST)(unsafe.Pointer(ast)).Fkind {
	case int32(_AST_MEMREF):
		fallthrough
	case int32(_AST_ARRAYREF):
		return libc.BoolUint8(m_true != 0)
	case int32(_AST_CONSTREF):
		return libc.BoolUint8(m_false != 0)
	case int32(_AST_FUNCCALL):
		fallthrough
	case int32(_AST_GOSUB):
		return libc.BoolUint8(m_true != 0)
	case int32(_AST_LOCAL_IDENTIFIER):
		fallthrough
	case int32(_AST_IDENTIFIER):
		sym = x__LookupAstSymbol(tls, cc, ast, libc.UintptrFromInt32(0))
		if !(sym != 0) {
			return libc.BoolUint8(m_true != 0)
		}
		switch (*_Symbol)(unsafe.Pointer(sym)).Fkind {
		case int32(_SYM_TEMPVAR):
			fallthrough
		case int32(_SYM_PARAMETER):
			fallthrough
		case int32(_SYM_RESULT):
			fallthrough
		case int32(_SYM_LOCALVAR):
			return libc.BoolUint8(int32(*(*uint32)(unsafe.Pointer(cc.x__curfunc + 1248))&0x400>>10) != libc.Int32FromInt32(0))
		default:
			return libc.BoolUint8(m_true != 0)
		}
		fallthrough
	default:
		return libc.BoolUint8(s__AstUsesMemory(tls, cc, (*_AST)(unsafe.Pointer(ast)).Fleft) != 0 || s__AstUsesMemory(tls, cc, (*_AST)(unsafe.Pointer(ast)).Fright) != 0)
	}
	return r
}

