//	 * lookdown(i : a, b, c..d, e) ->
//	 *      case i
//	 *        a: r := 1
//	 *        b: r := 2
//	 *        c..d: r:= 3+(i-c)
//	 *        e: r := 4+(d-c)
//	 * lookup(i : a, b, c..d, e) ->
//	 *      case i
//	 *        1: r := a
//	 *        2: r := b
//	 *        3..3+(d-c): r:= c+(i-3)
//	 *        4+(d-c): r := e
